import { TypeQuizQuestion } from "./quiz-types";
export const newQType1: TypeQuizQuestion[] = [
  // ── DIFFICULTY 1 (20 questions) ──
  { id: 451, type: 1, difficulty: 1 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Real-Life Scenarios", question: "A Type 1 notices their roommate left dirty dishes in the sink. What is their most likely internal reaction?", options: [{ letter: "A", text: "They feel anxious about potential conflict" }, { letter: "B", text: "They feel a rising irritation and an urge to clean or correct it" }, { letter: "C", text: "They feel sad that their roommate doesn't care about them" }, { letter: "D", text: "They shrug it off and forget about it" }], answer: "B", explanation: "Type 1s experience a visceral reaction to disorder. The dirty dishes activate their inner critic, creating tension between their desire to correct and their attempt to suppress frustration." },
  { id: 452, type: 1, difficulty: 1 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Real-Life Scenarios", question: "At work, a Type 1 is asked to submit a report quickly rather than perfectly. How do they typically feel?", options: [{ letter: "A", text: "Relieved that they can move on to something else" }, { letter: "B", text: "Physically uncomfortable submitting work below their standards" }, { letter: "C", text: "Indifferent, they adapt to whatever is asked" }, { letter: "D", text: "Excited by the challenge of speed" }], answer: "B", explanation: "Ones experience genuine distress when forced to produce subpar work. Their internal standards are not optional preferences but feel like moral imperatives." },
  { id: 453, type: 1, difficulty: 1 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Emotional Reactions", question: "When a Type 1 receives criticism, their first instinct is usually to:", options: [{ letter: "A", text: "Withdraw and process their feelings alone" }, { letter: "B", text: "Evaluate whether the criticism is fair and justified" }, { letter: "C", text: "Become confrontational and defensive" }, { letter: "D", text: "Seek reassurance from friends" }], answer: "B", explanation: "Ones filter criticism through their internal sense of fairness. If the criticism is valid, they'll agree and work to fix it. If it feels unjust, they experience righteous indignation." },
  { id: 454, type: 1, difficulty: 1 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Emotional Reactions", question: "How does a Type 1 typically respond when someone praises them?", options: [{ letter: "A", text: "They deflect, noting what they could have done better" }, { letter: "B", text: "They bask in it and seek more validation" }, { letter: "C", text: "They become suspicious of the person's motives" }, { letter: "D", text: "They feel energized and immediately take on more work" }], answer: "A", explanation: "The One's inner critic makes it difficult to accept praise. They immediately think of flaws the praiser didn't notice, making genuine compliments feel incomplete or undeserved." },
  { id: 455, type: 1, difficulty: 1 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Type in Pop Culture", question: "Which fictional character best exemplifies Type 1 traits of moral rigidity and an unrelenting inner critic?", options: [{ letter: "A", text: "Hermione Granger from Harry Potter" }, { letter: "B", text: "Captain America from Marvel" }, { letter: "C", text: "Jack Sparrow from Pirates of the Caribbean" }, { letter: "D", text: "Luna Lovegood from Harry Potter" }], answer: "B", explanation: "Captain America embodies the Type 1 pattern: an unwavering moral compass, willingness to stand alone for what's right, and discomfort with ethical compromises. His famous line 'I can do this all day' reflects the One's persistence." },
  { id: 456, type: 1, difficulty: 1 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Type in Pop Culture", question: "In The Office, which character demonstrates Type 1 qualities of following rules meticulously and correcting others?", options: [{ letter: "A", text: "Michael Scott" }, { letter: "B", text: "Angela Martin" }, { letter: "C", text: "Jim Halpert" }, { letter: "D", text: "Kevin Malone" }], answer: "B", explanation: "Angela Martin is a classic Type 1: rigid moral standards, judgmental of others' behavior, meticulous organization, suppressed anger that leaks out as disapproval, and a constant sense that she knows the 'right' way to do things." },
  { id: 457, type: 1, difficulty: 1 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Quick Identification", question: "Which of the following is most likely said by a Type 1?", options: [{ letter: "A", text: "Let's just see what happens and go with the flow" }, { letter: "B", text: "There's a right way and a wrong way to do this" }, { letter: "C", text: "I don't care how it gets done as long as people are happy" }, { letter: "D", text: "Rules are made to be broken" }], answer: "B", explanation: "This phrase captures the One's core worldview: there exists an objective standard of correctness, and it's their responsibility to identify and uphold it." },
  { id: 458, type: 1, difficulty: 1 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Quick Identification", question: "Which daily habit most suggests someone is a Type 1?", options: [{ letter: "A", text: "Making detailed to-do lists and feeling guilty when items remain unchecked" }, { letter: "B", text: "Journaling about their emotions and creative inspirations" }, { letter: "C", text: "Researching topics of interest for hours" }, { letter: "D", text: "Calling friends to check in on how they're doing" }], answer: "A", explanation: "The to-do list ritual with accompanying guilt is quintessentially Type 1: the drive to organize, the high standards for productivity, and the self-criticism when they fall short." },
  { id: 459, type: 1, difficulty: 1 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Common Phrases", question: "Which phrase is a Type 1 most likely to think but not say?", options: [{ letter: "A", text: "I wish people would just do things correctly" }, { letter: "B", text: "I hope everyone likes me" }, { letter: "C", text: "What's the most exciting option here?" }, { letter: "D", text: "I need more time alone to recharge" }], answer: "A", explanation: "Ones constantly notice errors and inefficiencies but often suppress voicing their critiques to avoid appearing judgmental, creating the classic 'resentment leak' they're known for." },
  { id: 460, type: 1, difficulty: 1 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Common Phrases", question: "Which of these is a common Type 1 self-talk pattern?", options: [{ letter: "A", text: "You should have done that better" }, { letter: "B", text: "Nobody understands how deep I feel" }, { letter: "C", text: "What if something goes wrong tomorrow?" }, { letter: "D", text: "I need to figure out what they want from me" }], answer: "A", explanation: "The 'should' voice is the hallmark of the One's superego. Their inner critic speaks in imperatives, should, must, ought, creating a constant pressure to improve." },
  { id: 461, type: 1, difficulty: 1 as 1|2|3|4|5, track1Day: 11, track2Day: 61, category: "Childhood Patterns", question: "What childhood experience is most formative for Type 1s?", options: [{ letter: "A", text: "Feeling abandoned or unloved by caregivers" }, { letter: "B", text: "Feeling they had to be good to earn love or avoid punishment" }, { letter: "C", text: "Being told they were special and unique" }, { letter: "D", text: "Having to figure things out on their own without guidance" }], answer: "B", explanation: "Ones typically grew up in environments where love felt conditional on being 'good.' They internalized that imperfection was dangerous, creating the inner critic as a survival mechanism." },
  { id: 462, type: 1, difficulty: 1 as 1|2|3|4|5, track1Day: 12, track2Day: 62, category: "Childhood Patterns", question: "As children, Type 1s often took on the role of:", options: [{ letter: "A", text: "The entertainer who kept everyone laughing" }, { letter: "B", text: "The responsible one who followed rules and helped maintain order" }, { letter: "C", text: "The rebel who questioned authority" }, { letter: "D", text: "The quiet observer who stayed in the background" }], answer: "B", explanation: "Young Ones often become the 'parentified child', taking on responsibilities beyond their age, policing themselves and siblings, and becoming the reliable, rule-following anchor of the family." },
  { id: 463, type: 1, difficulty: 1 as 1|2|3|4|5, track1Day: 13, track2Day: 63, category: "Communication Style", question: "How does a Type 1 typically give feedback to a colleague?", options: [{ letter: "A", text: "They avoid giving feedback to preserve the relationship" }, { letter: "B", text: "They provide specific, detailed corrections framed as helpful suggestions" }, { letter: "C", text: "They give vague encouragement to avoid hurting feelings" }, { letter: "D", text: "They are bluntly honest regardless of the impact" }], answer: "B", explanation: "Ones give meticulous feedback because they genuinely believe it helps. They frame corrections carefully, not to be mean, but because their inner standard demands precision and improvement." },
  { id: 464, type: 1, difficulty: 1 as 1|2|3|4|5, track1Day: 14, track2Day: 64, category: "Communication Style", question: "When texting, a Type 1 is most likely to:", options: [{ letter: "A", text: "Use proper grammar and punctuation, even in casual messages" }, { letter: "B", text: "Send long emotional paragraphs" }, { letter: "C", text: "Respond with single emojis or short slang" }, { letter: "D", text: "Take days to respond because they forgot" }], answer: "A", explanation: "The One's attention to correctness extends to communication. Many Ones feel uncomfortable sending messages with typos or poor grammar, even in informal contexts." },
  { id: 465, type: 1, difficulty: 1 as 1|2|3|4|5, track1Day: 15, track2Day: 65, category: "Real-Life Scenarios", question: "A Type 1 is on vacation. What thought is most likely to intrude?", options: [{ letter: "A", text: "I wonder what exciting adventures I'm missing elsewhere" }, { letter: "B", text: "I should be using this time more productively" }, { letter: "C", text: "I hope everyone at home is okay without me" }, { letter: "D", text: "I need to document every moment of this trip" }], answer: "B", explanation: "Ones struggle to relax because their inner critic doesn't take vacations. The 'should' voice continues operating, making leisure feel guilty or wasteful." },
  { id: 466, type: 1, difficulty: 1 as 1|2|3|4|5, track1Day: 16, track2Day: 66, category: "Emotional Reactions", question: "When a Type 1 witnesses someone cutting in line, they typically feel:", options: [{ letter: "A", text: "Anxious that conflict might break out" }, { letter: "B", text: "A strong sense of injustice and suppressed anger" }, { letter: "C", text: "Indifferent, it's not their problem" }, { letter: "D", text: "Sad for the person who must be in a hurry" }], answer: "B", explanation: "Fairness violations trigger the One's core anger. They may not confront the person, but they'll feel the injustice viscerally and may seethe internally about it." },
  { id: 467, type: 1, difficulty: 1 as 1|2|3|4|5, track1Day: 17, track2Day: 67, category: "Quick Identification", question: "Which organizational style most indicates a Type 1?", options: [{ letter: "A", text: "Creative chaos, they know where everything is in the mess" }, { letter: "B", text: "Color-coded systems with specific places for everything" }, { letter: "C", text: "Minimal possessions, only the essentials" }, { letter: "D", text: "Organized when others visit, messy when alone" }], answer: "B", explanation: "The One's need for order is internal and persistent, not performative. They organize for their own sense of rightness, not for others' approval." },
  { id: 468, type: 1, difficulty: 1 as 1|2|3|4|5, track1Day: 18, track2Day: 68, category: "Common Phrases", question: "A Type 1 apologizes. Which phrasing is most characteristic?", options: [{ letter: "A", text: "I'm sorry if you felt that way" }, { letter: "B", text: "I was wrong. I should have handled that differently and I'll do better" }, { letter: "C", text: "Sorry, my bad!" }, { letter: "D", text: "I'm sorry, please don't be mad at me" }], answer: "B", explanation: "Ones take responsibility seriously. Their apologies are specific, acknowledge the exact error, and include a commitment to improvement, reflecting their core drive toward integrity." },
  { id: 469, type: 1, difficulty: 1 as 1|2|3|4|5, track1Day: 19, track2Day: 69, category: "Childhood Patterns", question: "Which childhood memory is most characteristic of a Type 1?", options: [{ letter: "A", text: "Being praised for getting straight A's but feeling it wasn't enough" }, { letter: "B", text: "Being the class clown to get attention" }, { letter: "C", text: "Spending hours alone building imaginary worlds" }, { letter: "D", text: "Always having a large group of friends" }], answer: "A", explanation: "Young Ones often excelled academically but felt their achievements were never sufficient. The inner critic formed early, turning external expectations into internalized impossible standards." },
  { id: 470, type: 1, difficulty: 1 as 1|2|3|4|5, track1Day: 20, track2Day: 70, category: "Communication Style", question: "In an argument, a Type 1 is most likely to:", options: [{ letter: "A", text: "Shut down and refuse to engage" }, { letter: "B", text: "Cite specific facts and examples to prove their point is correct" }, { letter: "C", text: "Become emotional and cry" }, { letter: "D", text: "Agree with the other person to end the conflict" }], answer: "B", explanation: "Ones argue with evidence and logic because they believe in objective rightness. They present their case methodically, which can feel overwhelming to more feeling-oriented types." },
  // ── DIFFICULTY 2 (20 questions) ──
  { id: 471, type: 1, difficulty: 2 as 1|2|3|4|5, track1Day: 21, track2Day: 71, category: "Relationship Dynamics", question: "In a romantic relationship, what is a Type 1's biggest challenge?", options: [{ letter: "A", text: "Being too emotionally distant and unavailable" }, { letter: "B", text: "Unconsciously criticizing their partner's habits and choices" }, { letter: "C", text: "Being too dependent on their partner for validation" }, { letter: "D", text: "Losing their identity by merging with their partner" }], answer: "B", explanation: "The One's inner critic extends outward in intimate relationships. They may not intend to criticize, but their automatic noticing of 'what's wrong' creates a drip of corrections that partners experience as constant disapproval." },
  { id: 472, type: 1, difficulty: 2 as 1|2|3|4|5, track1Day: 22, track2Day: 72, category: "Relationship Dynamics", question: "Which type pairing often creates a 'reformer meets rebel' dynamic with Type 1?", options: [{ letter: "A", text: "Type 1 and Type 9" }, { letter: "B", text: "Type 1 and Type 7" }, { letter: "C", text: "Type 1 and Type 5" }, { letter: "D", text: "Type 1 and Type 2" }], answer: "B", explanation: "The 1-7 pairing creates classic tension: the One wants structure and correctness while the Seven wants freedom and spontaneity. They can complement each other (the 7 loosens the 1 up; the 1 grounds the 7) or clash intensely." },
  { id: 473, type: 1, difficulty: 2 as 1|2|3|4|5, track1Day: 23, track2Day: 73, category: "Defense Mechanisms", question: "What is the primary defense mechanism of Type 1?", options: [{ letter: "A", text: "Projection, attributing their feelings to others" }, { letter: "B", text: "Reaction formation, converting unacceptable impulses into their opposite" }, { letter: "C", text: "Intellectualization, retreating into abstract thinking" }, { letter: "D", text: "Displacement, redirecting emotions to a safer target" }], answer: "B", explanation: "Reaction formation is the One's signature defense: they transform unacceptable desires (laziness, anger, selfishness) into their opposites (productivity, composure, selflessness). The original impulse still exists but is buried." },
  { id: 474, type: 1, difficulty: 2 as 1|2|3|4|5, track1Day: 24, track2Day: 74, category: "Defense Mechanisms", question: "A Type 1 says 'I'm not angry, I'm just disappointed.' What defense pattern does this illustrate?", options: [{ letter: "A", text: "Denial of their anger passion through reframing" }, { letter: "B", text: "Healthy emotional regulation" }, { letter: "C", text: "Projection onto the other person" }, { letter: "D", text: "Dissociation from their body" }], answer: "A", explanation: "Ones reframe anger as 'disappointment' or 'frustration' because anger feels morally wrong to them. The distinction matters: disappointment implies a standard that wasn't met (acceptable), while anger implies loss of control (unacceptable)." },
  { id: 475, type: 1, difficulty: 2 as 1|2|3|4|5, track1Day: 25, track2Day: 75, category: "Conflict Style", question: "How does a Type 1 typically handle conflict?", options: [{ letter: "A", text: "They avoid it at all costs" }, { letter: "B", text: "They address it directly but frame their position as the objectively correct one" }, { letter: "C", text: "They become aggressive and dominating" }, { letter: "D", text: "They manipulate the situation behind the scenes" }], answer: "B", explanation: "Ones engage in conflict when they believe they're right (which is often). They present their case as factual rather than opinion-based, which can make others feel their perspective isn't being heard." },
  { id: 476, type: 1, difficulty: 2 as 1|2|3|4|5, track1Day: 26, track2Day: 76, category: "Conflict Style", question: "What is the 'resentment leak' pattern common in Type 1s?", options: [{ letter: "A", text: "Expressing anger openly in explosive outbursts" }, { letter: "B", text: "Suppressed anger seeping out as sighs, tight lips, clipped tone, or passive corrections" }, { letter: "C", text: "Directing anger inward, resulting in depression" }, { letter: "D", text: "Channeling anger into physical exercise" }], answer: "B", explanation: "Because Ones believe overt anger is wrong, their suppressed frustration 'leaks' through body language, tone, and small corrections. Others often sense the One's displeasure before the One acknowledges it themselves." },
  { id: 477, type: 1, difficulty: 2 as 1|2|3|4|5, track1Day: 27, track2Day: 77, category: "Shadow Work", question: "What is the primary shadow of Type 1?", options: [{ letter: "A", text: "Their need for attention and admiration" }, { letter: "B", text: "Their own desires for pleasure, rest, and imperfection" }, { letter: "C", text: "Their fear of being alone" }, { letter: "D", text: "Their competitive drive to outperform others" }], answer: "B", explanation: "The One's shadow contains everything they've deemed 'wrong': the desire to be lazy, messy, selfish, or hedonistic. Integration involves acknowledging these desires as human rather than sinful." },
  { id: 478, type: 1, difficulty: 2 as 1|2|3|4|5, track1Day: 28, track2Day: 78, category: "Shadow Work", question: "Why are Type 1s often unconsciously drawn to 'rule-breakers'?", options: [{ letter: "A", text: "They want to reform them" }, { letter: "B", text: "Rule-breakers express the freedom the One has repressed in themselves" }, { letter: "C", text: "They enjoy feeling morally superior" }, { letter: "D", text: "They mistake rebellion for strength" }], answer: "B", explanation: "The One's attraction to rebellious types reveals their shadow: the repressed desire for freedom from their own internal rules. Others who break rules without guilt represent the liberation the One secretly craves." },
  { id: 479, type: 1, difficulty: 2 as 1|2|3|4|5, track1Day: 29, track2Day: 79, category: "Parenting Style", question: "How does a Type 1 parent typically approach child-rearing?", options: [{ letter: "A", text: "Permissive, letting children find their own way" }, { letter: "B", text: "Structured with clear expectations, consistent rules, and emphasis on responsibility" }, { letter: "C", text: "Helicopter parenting driven by anxiety" }, { letter: "D", text: "Achievement-focused, pushing children toward success" }], answer: "B", explanation: "One parents create orderly households with clear moral expectations. At their best, they teach integrity and responsibility. At their worst, their children internalize the same harsh inner critic." },
  { id: 480, type: 1, difficulty: 2 as 1|2|3|4|5, track1Day: 30, track2Day: 80, category: "Parenting Style", question: "What is the biggest risk of Type 1 parenting?", options: [{ letter: "A", text: "Being too permissive and failing to set boundaries" }, { letter: "B", text: "Children internalizing that they must be perfect to be loved" }, { letter: "C", text: "Neglecting children due to workaholism" }, { letter: "D", text: "Creating dependency by doing everything for the child" }], answer: "B", explanation: "The One parent's constant corrections, even when well-intentioned, can teach children that love is conditional on performance. The child may develop their own punishing inner critic." },
  { id: 481, type: 1, difficulty: 2 as 1|2|3|4|5, track1Day: 31, track2Day: 81, category: "Attachment Style", question: "Which attachment style is most commonly associated with Type 1?", options: [{ letter: "A", text: "Anxious-preoccupied" }, { letter: "B", text: "Dismissive-avoidant" }, { letter: "C", text: "Secure with anxious tendencies" }, { letter: "D", text: "Fearful-avoidant" }], answer: "C", explanation: "Ones often present as securely attached on the surface due to their reliability and commitment, but underneath carry anxious tendencies, worrying about doing relationships 'right' and meeting their own standards as a partner." },
  { id: 482, type: 1, difficulty: 2 as 1|2|3|4|5, track1Day: 32, track2Day: 82, category: "Somatic Patterns", question: "Where do Type 1s typically hold tension in their body?", options: [{ letter: "A", text: "In their chest and throat" }, { letter: "B", text: "In their jaw, shoulders, and lower back" }, { letter: "C", text: "In their stomach and gut" }, { letter: "D", text: "Evenly distributed, they don't hold specific tension" }], answer: "B", explanation: "As a body center type, Ones hold anger as physical rigidity. The clenched jaw (suppressed words), tight shoulders (carrying responsibility), and stiff lower back (bracing against impulses) are classic somatic patterns." },
  { id: 483, type: 1, difficulty: 2 as 1|2|3|4|5, track1Day: 33, track2Day: 83, category: "Somatic Patterns", question: "How does repressed anger manifest physically in many Type 1s?", options: [{ letter: "A", text: "Panic attacks and shortness of breath" }, { letter: "B", text: "Headaches, teeth grinding, and muscle tension" }, { letter: "C", text: "Fatigue and oversleeping" }, { letter: "D", text: "Nervous tics and fidgeting" }], answer: "B", explanation: "The One's suppressed anger doesn't disappear, it lodges in the body. Bruxism (teeth grinding), tension headaches, and chronic muscle tightness are common physical manifestations of unexpressed resentment." },
  { id: 484, type: 1, difficulty: 2 as 1|2|3|4|5, track1Day: 34, track2Day: 84, category: "Coping Under Stress", question: "What is a healthy coping strategy for a Type 1 under stress?", options: [{ letter: "A", text: "Making even more detailed plans and working harder" }, { letter: "B", text: "Allowing themselves to be playful and spontaneous without guilt" }, { letter: "C", text: "Isolating to analyze what went wrong" }, { letter: "D", text: "Seeking validation that they did the right thing" }], answer: "B", explanation: "Healthy stress relief for Ones involves their integration direction toward Type 7: embracing joy, spontaneity, and imperfection. This loosens the grip of the inner critic and reconnects them with pleasure." },
  { id: 485, type: 1, difficulty: 2 as 1|2|3|4|5, track1Day: 35, track2Day: 85, category: "Coping Under Stress", question: "When a Type 1 is in an unhealthy stress pattern, they may begin to:", options: [{ letter: "A", text: "Become scattered and unreliable" }, { letter: "B", text: "Become moody, envious, and feel that nobody understands their suffering" }, { letter: "C", text: "Become aggressive and power-seeking" }, { letter: "D", text: "Become detached and emotionally flat" }], answer: "B", explanation: "Under stress, Ones move toward Type 4's unhealthy patterns: they become melodramatic, feel uniquely burdened, and believe nobody else holds themselves to such high standards. Self-pity replaces self-discipline." },
  { id: 486, type: 1, difficulty: 2 as 1|2|3|4|5, track1Day: 36, track2Day: 86, category: "Relationship Dynamics", question: "What does a Type 1 most need from their partner?", options: [{ letter: "A", text: "Constant excitement and new experiences" }, { letter: "B", text: "Appreciation for their efforts and reassurance that they're 'good enough'" }, { letter: "C", text: "Space and independence to pursue their interests" }, { letter: "D", text: "Someone who challenges and debates them intellectually" }], answer: "B", explanation: "Ones carry an exhausting internal burden of never feeling good enough. A partner who genuinely appreciates their efforts and reminds them they're loved despite imperfections provides the antidote they can't give themselves." },
  { id: 487, type: 1, difficulty: 2 as 1|2|3|4|5, track1Day: 37, track2Day: 87, category: "Shadow Work", question: "The concept of 'trapdoor behavior' in Type 1 refers to:", options: [{ letter: "A", text: "Sudden eruptions of the very behaviors they judge in others" }, { letter: "B", text: "Setting traps to catch others making mistakes" }, { letter: "C", text: "Escaping difficult conversations" }, { letter: "D", text: "Hiding their achievements out of false modesty" }], answer: "A", explanation: "Ones who rigidly suppress certain desires may periodically 'fall through a trapdoor' into the exact behavior they condemn: binge eating, secret affairs, angry outbursts. The repressed shadow demands expression." },
  { id: 488, type: 1, difficulty: 2 as 1|2|3|4|5, track1Day: 38, track2Day: 88, category: "Defense Mechanisms", question: "How does 'compartmentalization' serve Type 1s?", options: [{ letter: "A", text: "It helps them organize their schedule efficiently" }, { letter: "B", text: "It allows them to separate their 'imperfect' behaviors from their self-image as good" }, { letter: "C", text: "It helps them multitask at work" }, { letter: "D", text: "It protects them from emotional overwhelm" }], answer: "B", explanation: "Compartmentalization lets Ones maintain their self-image as moral and correct while engaging in behaviors that contradict their standards. The 'trapdoor' indulgence stays in a sealed mental box, separate from identity." },
  { id: 489, type: 1, difficulty: 2 as 1|2|3|4|5, track1Day: 39, track2Day: 89, category: "Conflict Style", question: "How does a 1w2 handle conflict differently from a 1w9?", options: [{ letter: "A", text: "1w2 avoids conflict entirely; 1w9 is more confrontational" }, { letter: "B", text: "1w2 addresses conflict through personal appeals; 1w9 withdraws into principled silence" }, { letter: "C", text: "1w2 uses humor; 1w9 uses logic" }, { letter: "D", text: "There is no meaningful difference" }], answer: "B", explanation: "The Two wing makes 1w2s more interpersonal in conflict, they appeal to relationships and duty. The Nine wing makes 1w9s more avoidant, they stiffen, withdraw, and wait for the other person to realize their error." },
  { id: 490, type: 1, difficulty: 2 as 1|2|3|4|5, track1Day: 40, track2Day: 90, category: "Attachment Style", question: "How does a Type 1's attachment style affect their dating life?", options: [{ letter: "A", text: "They fall in love quickly and intensely" }, { letter: "B", text: "They create mental checklists and evaluate partners against their standards" }, { letter: "C", text: "They avoid dating altogether" }, { letter: "D", text: "They date multiple people simultaneously to compare" }], answer: "B", explanation: "The One's inner evaluator extends to romantic prospects. They may unconsciously score dates against criteria for the 'right' partner, making it hard to simply enjoy getting to know someone." },
  // ── DIFFICULTY 3 (20 questions) ──
  { id: 491, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 41, track2Day: 91, category: "Workplace Archetypes", question: "What leadership style is most natural for a Type 1?", options: [{ letter: "A", text: "Charismatic and inspirational" }, { letter: "B", text: "Process-oriented with clear standards, consistent enforcement, and lead-by-example ethic" }, { letter: "C", text: "Laissez-faire, trusting teams to self-organize" }, { letter: "D", text: "Competitive and results-focused above all else" }], answer: "B", explanation: "One leaders create structured, fair environments. They lead by modeling the behavior they expect, establish clear processes, and hold everyone (including themselves) to the same standard." },
  { id: 492, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 42, track2Day: 92, category: "Workplace Archetypes", question: "What is a Type 1 manager's typical blind spot?", options: [{ letter: "A", text: "Failure to set clear expectations" }, { letter: "B", text: "Micromanaging because they don't trust others to meet their standards" }, { letter: "C", text: "Being too focused on relationships over results" }, { letter: "D", text: "Making impulsive decisions" }], answer: "B", explanation: "One managers often micromanage not from a need for control (like Eights) but from genuine doubt that others will do it 'right.' Their standards feel objective to them, making delegation feel risky." },
  { id: 493, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 43, track2Day: 93, category: "Spiritual Traditions", question: "In contemplative Enneagram traditions, what is the 'virtue' that Type 1 develops through growth?", options: [{ letter: "A", text: "Humility" }, { letter: "B", text: "Serenity" }, { letter: "C", text: "Courage" }, { letter: "D", text: "Innocence" }], answer: "B", explanation: "Serenity is the One's virtue, the deep acceptance that reality is already fundamentally okay. It dissolves the driving belief that everything must be fixed and allows the One to release their compulsive reforming." },
  { id: 494, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 44, track2Day: 94, category: "Spiritual Traditions", question: "How does the Enneagram's concept of 'Holy Perfection' relate to Type 1?", options: [{ letter: "A", text: "It validates their drive to make everything perfect" }, { letter: "B", text: "It teaches that reality is already inherently perfect, dissolving the need to fix" }, { letter: "C", text: "It is unrelated to Type 1" }, { letter: "D", text: "It refers to perfecting one's meditation practice" }], answer: "B", explanation: "Holy Perfection (the One's Holy Idea from Ichazo) means recognizing that existence is already whole and complete. This is the antidote to the One's fixation that everything is broken and needs repair." },
  { id: 495, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 45, track2Day: 95, category: "Enneagram x MBTI", question: "Which MBTI type is most commonly found among Enneagram Type 1s?", options: [{ letter: "A", text: "ENFP" }, { letter: "B", text: "ISTJ" }, { letter: "C", text: "ENTP" }, { letter: "D", text: "INFP" }], answer: "B", explanation: "ISTJ (Introverted Sensing, Thinking, Judging) shares the One's preference for structure, rules, duty, and established procedures. Both types value reliability, thoroughness, and doing things the 'correct' way." },
  { id: 496, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 46, track2Day: 96, category: "Enneagram x MBTI", question: "How might a Type 1 with ENFJ cognitive functions differ from a typical One?", options: [{ letter: "A", text: "They would be less concerned with correctness" }, { letter: "B", text: "Their reforming drive would focus on people and social systems rather than procedures" }, { letter: "C", text: "They would not identify as a Type 1" }, { letter: "D", text: "They would be identical to an ISTJ One" }], answer: "B", explanation: "An ENFJ One channels the reforming drive through Fe (extraverted feeling), they focus on improving social dynamics, mentoring others, and creating ethical communities rather than perfecting systems or procedures." },
  { id: 497, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 47, track2Day: 97, category: "Instinct x Wing Combos", question: "How does a social (so) Type 1w2 typically present?", options: [{ letter: "A", text: "As a withdrawn perfectionist focused on personal standards" }, { letter: "B", text: "As a moral crusader focused on reforming society and helping communities" }, { letter: "C", text: "As an intense, competitive achiever" }, { letter: "D", text: "As a quiet, studious intellectual" }], answer: "B", explanation: "The social instinct directs the One's reforming energy outward to society, while the Two wing adds warmth and people-focus. This combination creates the archetypal activist, social reformer, or community organizer." },
  { id: 498, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 48, track2Day: 98, category: "Instinct x Wing Combos", question: "How does a self-preservation (sp) 1w9 differ from a sexual (sx) 1w2?", options: [{ letter: "A", text: "sp 1w9 focuses on personal routines and domestic order; sx 1w2 focuses on reforming their intimate partner" }, { letter: "B", text: "They are essentially the same" }, { letter: "C", text: "sp 1w9 is more social; sx 1w2 is more withdrawn" }, { letter: "D", text: "sp 1w9 is more emotional; sx 1w2 is more logical" }], answer: "A", explanation: "The sp 1w9 channels perfectionism into personal environment and health routines, creating a controlled, orderly personal life. The sx 1w2 directs reforming energy toward their closest relationship, wanting to improve their partner." },
  { id: 499, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 49, track2Day: 99, category: "Tritype Deep Dives", question: "What characterizes the 1-3-5 tritype?", options: [{ letter: "A", text: "The 'social butterfly', warm, connected, and people-oriented" }, { letter: "B", text: "The 'competent perfectionist', driven by standards, achievement, and knowledge" }, { letter: "C", text: "The 'creative rebel', unconventional and emotionally intense" }, { letter: "D", text: "The 'loyal helper', devoted to community and service" }], answer: "B", explanation: "The 1-3-5 tritype combines the One's perfectionism, the Three's achievement drive, and the Five's knowledge-seeking. This creates someone who is highly competent, efficient, and holds themselves to exacting intellectual and moral standards." },
  { id: 500, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 50, track2Day: 100, category: "Tritype Deep Dives", question: "How does the 1-2-6 tritype typically manifest?", options: [{ letter: "A", text: "As an independent, emotionally detached thinker" }, { letter: "B", text: "As a dutiful, service-oriented person who enforces rules to protect their community" }, { letter: "C", text: "As a creative individualist" }, { letter: "D", text: "As an adventurous free spirit" }], answer: "B", explanation: "The 1-2-6 combines moral standards (1), desire to help (2), and loyalty to group (6). This tritype creates the quintessential 'responsible community member', someone who serves through structure and moral leadership." },
  { id: 501, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 51, track2Day: 1, category: "Growth Practices", question: "Which practice most effectively supports Type 1 growth?", options: [{ letter: "A", text: "Setting even higher standards to push themselves further" }, { letter: "B", text: "Mindfulness meditation that observes the inner critic without acting on it" }, { letter: "C", text: "Competitive activities that channel their perfectionism" }, { letter: "D", text: "Journaling about others' mistakes to process frustration" }], answer: "B", explanation: "Mindfulness helps Ones create space between the inner critic's voice and their response. By observing judgmental thoughts without attachment, they learn that thoughts are not commands and imperfection is not catastrophic." },
  { id: 502, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 52, track2Day: 2, category: "Growth Practices", question: "Why is intentional 'imperfection practice' recommended for Type 1s?", options: [{ letter: "A", text: "It wastes less time than perfectionism" }, { letter: "B", text: "It safely proves that imperfection doesn't lead to catastrophe, weakening the inner critic" }, { letter: "C", text: "It makes them more likable to others" }, { letter: "D", text: "It doesn't work for Type 1s" }], answer: "B", explanation: "Deliberately leaving something imperfect (a bed unmade, an email unsent) provides experiential evidence that the world doesn't collapse. This slowly retrains the nervous system that was wired to equate imperfection with danger." },
  { id: 503, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 53, track2Day: 3, category: "Naranjo's Character Types", question: "In Naranjo's system, what is the 'fixation' of Type 1?", options: [{ letter: "A", text: "Flattery" }, { letter: "B", text: "Resentment" }, { letter: "C", text: "Vanity" }, { letter: "D", text: "Indolence" }], answer: "B", explanation: "Naranjo identified resentment as the One's cognitive fixation, the habitual mental pattern of comparing reality to an ideal and feeling frustrated by the gap. This resentment is directed at self, others, and the world itself." },
  { id: 504, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 54, track2Day: 4, category: "Naranjo's Character Types", question: "Naranjo described the Type 1 character as having an 'over-developed superego.' What does this mean practically?", options: [{ letter: "A", text: "They are highly creative and imaginative" }, { letter: "B", text: "Their internal moral authority is so strong it overrides desires, needs, and spontaneity" }, { letter: "C", text: "They are natural leaders" }, { letter: "D", text: "They have strong religious convictions" }], answer: "B", explanation: "The One's superego operates like an internal dictator that suppresses the id (desires, impulses, pleasure). This creates reliable, ethical behavior but at the cost of joy, spontaneity, and self-compassion." },
  { id: 505, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 55, track2Day: 5, category: "Workplace Archetypes", question: "When receiving performance feedback, a Type 1 employee typically:", options: [{ letter: "A", text: "Dismisses criticism and focuses only on praise" }, { letter: "B", text: "Fixates on any negative feedback while minimizing positive feedback" }, { letter: "C", text: "Has an emotional outburst" }, { letter: "D", text: "Ignores feedback entirely and trusts their own judgment" }], answer: "B", explanation: "The One's inner critic amplifies negative feedback (confirming what it already suspected) and dismisses praise (it doesn't match their internal narrative). A single criticism in a glowing review will be the only thing they remember." },
  { id: 506, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 56, track2Day: 6, category: "Instinct x Wing Combos", question: "Which instinct/wing combination makes a Type 1 look most like a Type 8?", options: [{ letter: "A", text: "sp 1w9" }, { letter: "B", text: "sx 1w2" }, { letter: "C", text: "so 1w9" }, { letter: "D", text: "sp 1w2" }], answer: "B", explanation: "The sexual (sx) 1w2 is the most intense One variant. The sx instinct adds heat and intensity while the Two wing adds interpersonal directness. This combination can look confrontational and forceful, resembling an Eight, but motivated by moral rightness rather than power." },
  { id: 507, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 57, track2Day: 7, category: "Growth Practices", question: "Why does Type 1 growth involve moving toward Type 7 qualities?", options: [{ letter: "A", text: "Because Type 7 is the opposite of Type 1" }, { letter: "B", text: "Because embracing joy, spontaneity, and abundance dissolves the One's rigid inner critic" }, { letter: "C", text: "Because Type 7 is objectively the healthiest type" }, { letter: "D", text: "It doesn't, Ones should avoid Type 7 behavior" }], answer: "B", explanation: "The One's integration to 7 represents embracing what they've most denied: spontaneous joy, playfulness, and the ability to see possibilities rather than problems. This doesn't make them irresponsible, it makes them whole." },
  { id: 508, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 58, track2Day: 8, category: "Enneagram x MBTI", question: "A Type 1 with strong Fi (introverted feeling) would most likely:", options: [{ letter: "A", text: "Base their standards on deeply personal values rather than external rules" }, { letter: "B", text: "Be more social and outgoing than typical Ones" }, { letter: "C", text: "Not identify as a Type 1" }, { letter: "D", text: "Be less concerned with morality" }], answer: "A", explanation: "Fi-dominant Ones (like INFP Ones) derive their standards from internal values rather than societal norms. Their inner critic is calibrated to personal authenticity rather than conventional correctness." },
  { id: 509, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 59, track2Day: 9, category: "Spiritual Traditions", question: "Which contemplative practice aligns most with the One's path of transformation?", options: [{ letter: "A", text: "Visualization of future achievements" }, { letter: "B", text: "Loving-kindness (metta) meditation directed toward oneself" }, { letter: "C", text: "Analytical study of sacred texts" }, { letter: "D", text: "Fasting and ascetic discipline" }], answer: "B", explanation: "Self-directed loving-kindness directly addresses the One's core wound. By intentionally generating compassion toward themselves (especially their imperfections), they soften the inner critic that has run their life." },
  { id: 510, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 60, track2Day: 10, category: "Naranjo's Character Types", question: "What did Naranjo mean by Type 1's 'perfectionism as aggression'?", options: [{ letter: "A", text: "Ones are physically aggressive people" }, { letter: "B", text: "Their relentless correcting is a socially acceptable way to express the anger they deny" }, { letter: "C", text: "They aggressively pursue career goals" }, { letter: "D", text: "They are aggressive negotiators" }], answer: "B", explanation: "Naranjo observed that the One's constant improving, correcting, and criticizing is actually their anger expressing itself through a morally acceptable channel. They get to be angry at what's 'wrong' without admitting they're angry." },
  // ── DIFFICULTY 4 (20 questions) ──
  { id: 511, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 61, track2Day: 11, category: "Panel Wisdom", question: "In an Enneagram panel, a participant says: 'I don't think of myself as angry. I just have strong opinions about how things should be done.' This is most characteristic of:", options: [{ letter: "A", text: "Type 8's denial of vulnerability" }, { letter: "B", text: "Type 1's reframing of anger as righteous standards" }, { letter: "C", text: "Type 3's image management" }, { letter: "D", text: "Type 6's projection of authority" }], answer: "B", explanation: "This classic panel statement reveals the One's core pattern: their anger is so thoroughly reframed as 'standards' that they genuinely don't experience it as anger. The passion of anger hides behind moral conviction." },
  { id: 512, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 62, track2Day: 12, category: "Panel Wisdom", question: "A panel participant shares: 'When I finally let myself be messy and imperfect, I cried. I didn't realize how exhausted I was from holding it all together.' This breakthrough moment is most characteristic of:", options: [{ letter: "A", text: "Type 3 dropping their performance mask" }, { letter: "B", text: "Type 1 releasing the grip of the inner critic" }, { letter: "C", text: "Type 5 allowing emotional expression" }, { letter: "D", text: "Type 6 trusting themselves" }], answer: "B", explanation: "This describes the One's cathartic moment of integration, when the exhausting effort of maintaining perfection is finally released. The tears represent decades of suppressed self-compassion breaking through." },
  { id: 513, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 63, track2Day: 13, category: "Ichazo Fixations", question: "In Oscar Ichazo's system, what is the 'Trap' of Type 1?", options: [{ letter: "A", text: "Efficiency" }, { letter: "B", text: "Perfection" }, { letter: "C", text: "Security" }, { letter: "D", text: "Freedom" }], answer: "B", explanation: "Ichazo identified 'Perfection' as the One's trap, the seductive belief that if they just try harder, they can achieve a flawless state. This trap keeps them perpetually striving, never arriving at the goodness they seek." },
  { id: 514, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 64, track2Day: 14, category: "Ichazo Fixations", question: "What is the 'Holy Idea' that Type 1 has lost connection with, according to Ichazo?", options: [{ letter: "A", text: "Holy Omniscience" }, { letter: "B", text: "Holy Perfection, the recognition that reality is already perfect as it is" }, { letter: "C", text: "Holy Will" }, { letter: "D", text: "Holy Origin" }], answer: "B", explanation: "Holy Perfection doesn't mean everything is flawless but that reality is inherently complete and whole. The One has lost this knowing, replacing it with the ego belief that everything is broken and needs their correction." },
  { id: 515, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 65, track2Day: 15, category: "Object Relations Deep", question: "In the Hornevian groups, Type 1 belongs to the 'Compliant' (Dutiful) group. How does this manifest?", options: [{ letter: "A", text: "Ones comply with external authority without question" }, { letter: "B", text: "Ones comply with their internalized superego, moving toward people through duty and moral obligation" }, { letter: "C", text: "Ones comply with social norms to fit in" }, { letter: "D", text: "Ones are not actually compliant" }], answer: "B", explanation: "Karen Horney's 'moving toward' people manifests in Ones not as people-pleasing but as dutiful compliance with their own internalized moral authority. They serve and improve others out of obligation, not warmth." },
  { id: 516, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 66, track2Day: 16, category: "Object Relations Deep", question: "How does Type 1's relationship with the 'frustration' object relation affect their behavior?", options: [{ letter: "A", text: "They are frustrated with themselves for not finding love" }, { letter: "B", text: "They experience chronic dissatisfaction because reality never matches their internal ideal" }, { letter: "C", text: "They frustrate others intentionally" }, { letter: "D", text: "They are not part of the frustration group" }], answer: "B", explanation: "Type 1, along with Types 4 and 7, belongs to the 'frustration' group. Ones are perpetually frustrated because the gap between 'what is' and 'what should be' can never fully close, the ideal always recedes." },
  { id: 517, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 67, track2Day: 17, category: "Counter-Instinctual Combos", question: "The sexual (sx) Type 1 is considered the 'countertype' of the Ones. Why?", options: [{ letter: "A", text: "Because sx Ones don't have an inner critic" }, { letter: "B", text: "Because sx Ones express their reforming zeal through intense personal relationships rather than suppressing it" }, { letter: "C", text: "Because sx Ones are more like Type 7s" }, { letter: "D", text: "The sx One is not actually the countertype" }], answer: "B", explanation: "The sx One is the countertype because they direct their perfectionism into intimate relationships with passionate intensity, rather than the restrained, rule-following behavior associated with typical Ones. They can look like Eights or Fours." },
  { id: 518, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 68, track2Day: 18, category: "Counter-Instinctual Combos", question: "How does the self-preservation One (sp1) express their perfectionism differently from other One subtypes?", options: [{ letter: "A", text: "Through anxiety about money and career" }, { letter: "B", text: "Through meticulous control over their physical environment, diet, routines, and personal habits" }, { letter: "C", text: "Through social activism" }, { letter: "D", text: "They don't express perfectionism" }], answer: "B", explanation: "The sp One channels perfectionism into the material realm: the home must be organized, the body maintained, routines optimized. They are the most 'classic' One, orderly, disciplined, and focused on personal correctness." },
  { id: 519, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 69, track2Day: 19, category: "Differential Diagnosis", question: "Both Type 1 and Type 6 can be rule-followers. How do you distinguish them?", options: [{ letter: "A", text: "Ones follow rules because they believe in moral rightness; Sixes follow rules for safety and group belonging" }, { letter: "B", text: "They cannot be distinguished" }, { letter: "C", text: "Ones are always leaders; Sixes are always followers" }, { letter: "D", text: "Ones are emotional; Sixes are rational" }], answer: "A", explanation: "The motivation differs fundamentally: the One follows rules because breaking them would make them morally wrong (anger-based). The Six follows rules because breaking them threatens their security and support systems (fear-based)." },
  { id: 520, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 70, track2Day: 20, category: "Differential Diagnosis", question: "A person is highly organized, achievement-driven, and concerned about image. Are they more likely Type 1 or Type 3?", options: [{ letter: "A", text: "Type 1, because all organized people are Ones" }, { letter: "B", text: "Ask why: if driven by internal moral standards → Type 1; if driven by how others perceive their success → Type 3" }, { letter: "C", text: "Type 3, because all achievers are Threes" }, { letter: "D", text: "Neither, they're a Type 6" }], answer: "B", explanation: "The diagnostic key is motivation. Ones organize because it's 'right'; Threes organize because it looks successful. Ones are frustrated when things aren't correct; Threes are frustrated when things don't project the right image." },
  { id: 521, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 71, track2Day: 21, category: "Historical Enneagram", question: "Which Enneagram author is most associated with the concept of 'Levels of Development' that describes healthy to unhealthy Type 1 behavior?", options: [{ letter: "A", text: "Claudio Naranjo" }, { letter: "B", text: "Don Richard Riso" }, { letter: "C", text: "Oscar Ichazo" }, { letter: "D", text: "Helen Palmer" }], answer: "B", explanation: "Don Richard Riso (with Russ Hudson) developed the Levels of Development framework, nine levels from healthy to unhealthy for each type. For Ones, this ranges from Level 1 (wise, accepting) to Level 9 (punitive, obsessive, cruel)." },
  { id: 522, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 72, track2Day: 22, category: "Historical Enneagram", question: "In the Enneagram's historical development, the connection between Type 1 and anger was first systematically described by:", options: [{ letter: "A", text: "George Gurdjieff" }, { letter: "B", text: "Claudio Naranjo, drawing on Ichazo's protoanaylsis" }, { letter: "C", text: "Sigmund Freud" }, { letter: "D", text: "Carl Jung" }], answer: "B", explanation: "Naranjo was the first to systematically connect each Enneagram type to a specific passion/emotional pattern. He drew on Ichazo's proto-analysis framework and his own psychotherapy experience to articulate the One's anger pattern." },
  { id: 523, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 73, track2Day: 23, category: "Integration/Disintegration Chains", question: "When a Type 1 moves to their stress point (Type 4), what is the progression of behaviors?", options: [{ letter: "A", text: "Increased efficiency → burnout → withdrawal" }, { letter: "B", text: "Intensified criticism → self-pity → melancholy and feeling misunderstood" }, { letter: "C", text: "More social engagement → overcommitment → collapse" }, { letter: "D", text: "Greater assertiveness → aggression → isolation" }], answer: "B", explanation: "The One's disintegration to 4 follows a recognizable pattern: their inner critic intensifies until it turns fully inward, producing moody self-pity and the belief that nobody else suffers as much from trying to be good." },
  { id: 524, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 74, track2Day: 24, category: "Integration/Disintegration Chains", question: "What does healthy integration to Type 7 look like for a One?", options: [{ letter: "A", text: "Becoming irresponsible and abandoning their values" }, { letter: "B", text: "Maintaining integrity while embracing joy, humor, and the ability to enjoy imperfection" }, { letter: "C", text: "Becoming scattered and unfocused" }, { letter: "D", text: "Seeking constant stimulation and distraction" }], answer: "B", explanation: "Healthy Seven integration doesn't erase the One's values, it adds lightness. They can laugh at themselves, enjoy spontaneous experiences, and hold their standards with an open hand rather than a clenched fist." },
  { id: 525, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 75, track2Day: 25, category: "Ichazo Fixations", question: "What is the relationship between Type 1's 'passion' (anger) and their 'fixation' (resentment)?", options: [{ letter: "A", text: "They are the same thing" }, { letter: "B", text: "Anger is the emotional energy; resentment is the mental pattern of comparing and judging that sustains it" }, { letter: "C", text: "Resentment causes anger" }, { letter: "D", text: "They are unrelated" }], answer: "B", explanation: "In Ichazo's framework, the passion (anger) is the emotional fuel while the fixation (resentment) is the cognitive pattern that keeps it burning. The mind constantly compares reality to ideals (resentment), which generates the emotional response (anger)." },
  // ── DIFFICULTY 5 (20 questions) ──
  { id: 526, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 76, track2Day: 26, category: "Panel Wisdom", question: "A panelist says: 'I spent years in therapy before I realized my inner critic isn't me, it's a mechanism. When I first heard it as something separate, I wept with relief.' This transformative insight is characteristic of:", options: [{ letter: "A", text: "Type 4 discovering they are not their emotions" }, { letter: "B", text: "Type 1 differentiating their true self from their superego" }, { letter: "C", text: "Type 5 connecting with their feelings" }, { letter: "D", text: "Type 9 waking up to their own desires" }], answer: "B", explanation: "This is the One's pivotal growth moment: recognizing the inner critic as a defense mechanism rather than their identity. This separation (called 'disidentification') is the beginning of self-compassion and the end of the critic's totalitarian rule." },
  { id: 527, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 77, track2Day: 27, category: "Ichazo Fixations", question: "Ichazo described Type 1's 'Ego-Resentment.' How does this differ from ordinary resentment?", options: [{ letter: "A", text: "It is stronger than normal resentment" }, { letter: "B", text: "It is a structural ego pattern, a lens through which ALL of reality is filtered as deficient" }, { letter: "C", text: "It only applies to specific people" }, { letter: "D", text: "It refers to others' resentment toward the One" }], answer: "B", explanation: "Ego-Resentment in Ichazo's system is not situational anger but a fundamental perceptual filter. The One's ego literally cannot see reality without noticing what's wrong with it. Every experience passes through the deficiency detector." },
  { id: 528, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 78, track2Day: 28, category: "Object Relations Deep", question: "How does the 'frustration' object relation in Type 1 differ from the same dynamic in Type 4?", options: [{ letter: "A", text: "They are identical" }, { letter: "B", text: "Ones are frustrated that reality isn't correct enough; Fours are frustrated that reality isn't deep/authentic enough" }, { letter: "C", text: "Ones don't experience frustration" }, { letter: "D", text: "Fours don't experience frustration" }], answer: "B", explanation: "Both types share the 'frustration' stance, a chronic sense that something is missing. But the One seeks moral/functional perfection while the Four seeks emotional/aesthetic completeness. The ideal they're chasing differs fundamentally." },
  { id: 529, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 79, track2Day: 29, category: "Counter-Instinctual Combos", question: "Naranjo described the social One as having a quality of 'non-adaptability.' What does this mean?", options: [{ letter: "A", text: "They can't adapt to new technology" }, { letter: "B", text: "They rigidly hold to their moral position even when the social group disagrees, seeing themselves as the standard others should follow" }, { letter: "C", text: "They are socially awkward" }, { letter: "D", text: "They refuse to change jobs" }], answer: "B", explanation: "The social One (so1) believes they represent the correct moral standard for the group. Rather than adapting to social norms, they expect the group to adapt to their standards. This creates the 'preacher' or 'moral authority' archetype." },
  { id: 530, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 80, track2Day: 30, category: "Differential Diagnosis", question: "A client presents as highly principled, somewhat rigid, and angry about social injustice. They could be Type 1 or Type 6 counterphobic. The key differentiator is:", options: [{ letter: "A", text: "Type 1 acts from internal moral certainty; counterphobic 6 acts from the need to overcome their own fear" }, { letter: "B", text: "There is no way to tell them apart" }, { letter: "C", text: "Type 1 is always calm; Type 6 is always anxious" }, { letter: "D", text: "Only their childhood can distinguish them" }], answer: "A", explanation: "The One's conviction comes from a place of internal certainty, they know what's right. The counterphobic Six's activism is fueled by an underlying anxiety they're overcoming through confrontation. One feels righteous; Six feels brave." },
  { id: 531, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 81, track2Day: 31, category: "Integration/Disintegration Chains", question: "In the full disintegration chain, a very unhealthy One (moving to 4, then 4→2) might exhibit:", options: [{ letter: "A", text: "Manic productivity and overwork" }, { letter: "B", text: "Self-pity followed by manipulative demands for appreciation of their suffering" }, { letter: "C", text: "Complete emotional shutdown" }, { letter: "D", text: "Aggressive confrontation" }], answer: "B", explanation: "The deep disintegration chain 1→4→2 shows the One moving from rigid perfectionism into moody self-pity (4), then into manipulative claims on others' attention and gratitude (unhealthy 2): 'After all I've done, after all I've suffered...'" },
  { id: 532, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 82, track2Day: 32, category: "Historical Enneagram", question: "At Riso-Hudson Level 7 (unhealthy), what characterizes the Type 1?", options: [{ letter: "A", text: "Creative expression and emotional openness" }, { letter: "B", text: "Inflexible, self-righteous, and intolerant, the 'closed-minded bigot' who can justify cruelty in the name of virtue" }, { letter: "C", text: "Withdrawal from all social contact" }, { letter: "D", text: "Chaotic and impulsive behavior" }], answer: "B", explanation: "At Level 7, the One's inner critic has completely externalized. They become harsh judges who believe their cruelty is righteous punishment. Historical figures who committed atrocities 'for the greater good' often exemplify this level." },
  { id: 533, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 83, track2Day: 33, category: "Panel Wisdom", question: "A panelist shares: 'The hardest thing was realizing that my 'high standards' were actually a wall I built to avoid being vulnerable.' This insight reveals:", options: [{ letter: "A", text: "That the One's perfectionism serves a protective function against vulnerability and intimacy" }, { letter: "B", text: "That they don't actually have high standards" }, { letter: "C", text: "That they are mistyped as a One" }, { letter: "D", text: "That standards are always unhealthy" }], answer: "A", explanation: "Advanced One work reveals that perfectionism isn't just about being 'good', it's also an armor against vulnerability. If everything is controlled and correct, the One never has to risk the messiness of genuine emotional exposure." },
  { id: 534, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 84, track2Day: 34, category: "Ichazo Fixations", question: "What is the relationship between Holy Perfection and the One's virtue of Serenity?", options: [{ letter: "A", text: "They are unrelated concepts" }, { letter: "B", text: "Holy Perfection is the cognitive realization; Serenity is the emotional state that arises when the One truly grasps that reality is already whole" }, { letter: "C", text: "Serenity leads to Holy Perfection" }, { letter: "D", text: "They are the same thing expressed differently" }], answer: "B", explanation: "In Ichazo's framework, Holy Perfection (cognitive) and Serenity (emotional) are complementary aspects of the One's liberation. When the mind truly sees that reality is whole, the heart naturally relaxes into serenity, the anger dissolves." },
  { id: 535, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 85, track2Day: 35, category: "Object Relations Deep", question: "Karen Horney's concept of the 'idealized self-image' applies powerfully to Type 1. What is their idealized image?", options: [{ letter: "A", text: "The successful, admired achiever" }, { letter: "B", text: "The morally perfect, consistently right, self-disciplined person who never makes mistakes" }, { letter: "C", text: "The wise, knowledgeable expert" }, { letter: "D", text: "The strong, invulnerable protector" }], answer: "B", explanation: "Horney's idealized image for Ones is someone of absolute moral purity and correctness. The One strives to become this impossible ideal, and every deviation from it triggers the inner critic's punishment. This image is the prison that growth must dismantle." },
  { id: 536, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 86, track2Day: 36, category: "Counter-Instinctual Combos", question: "According to Beatrice Chestnut, what makes the sexual One the 'countertype' specifically?", options: [{ letter: "A", text: "They don't have an inner critic" }, { letter: "B", text: "Instead of suppressing anger behind composure, they feel entitled to express their reforming drive with heat and intensity in intimate bonds" }, { letter: "C", text: "They are the happiest One subtype" }, { letter: "D", text: "They look like Type 9s" }], answer: "B", explanation: "The sx One is counter to the type because while most Ones suppress anger (reaction formation), the sexual One channels it into passionate intensity within close relationships. They feel a right to reform their partner and express frustration directly." },
  { id: 537, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 87, track2Day: 37, category: "Differential Diagnosis", question: "A client is moralistic, detail-oriented, and suppresses emotion. They could be Type 1 or an ISTJ without being a One. What definitively identifies the Enneagram One?", options: [{ letter: "A", text: "The presence of anger as the core emotional driver, masked by reaction formation" }, { letter: "B", text: "Being organized" }, { letter: "C", text: "Following rules" }, { letter: "D", text: "Being introverted" }], answer: "A", explanation: "Behavioral traits (organization, rule-following) can stem from many sources. What makes someone a Type 1 specifically is the anger-based emotional pattern: the constant inner comparison, the suppressed resentment, and the reaction formation defense, not the surface behaviors." },
  { id: 538, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 88, track2Day: 38, category: "Integration/Disintegration Chains", question: "What does the One's 'second integration' (1→7→5) look like in practice?", options: [{ letter: "A", text: "Abandoning all standards" }, { letter: "B", text: "Gaining joy and spontaneity (7), then deepening into contemplative wisdom and detached acceptance (5)" }, { letter: "C", text: "Becoming increasingly scattered and isolated" }, { letter: "D", text: "Returning to rigid standards" }], answer: "B", explanation: "The extended integration path 1→7→5 represents full liberation: first gaining lightness and joy (7), then developing the Five's capacity for objective observation without judgment. The result is a wise, joyful person who sees clearly without needing to fix." },
  { id: 539, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 89, track2Day: 39, category: "Historical Enneagram", question: "How did Gurdjieff's concept of 'chief feature' relate to what we now call the Type 1 pattern?", options: [{ letter: "A", text: "He didn't address it" }, { letter: "B", text: "The chief feature of vanity/internal considering, the One's fixation on how they measure up to their own standard, is a form of spiritual sleep" }, { letter: "C", text: "He saw it as the healthiest pattern" }, { letter: "D", text: "He equated it with physical weakness" }], answer: "B", explanation: "Gurdjieff taught that each person has a 'chief feature' that keeps them mechanically asleep. For the One pattern, this is the automatic comparison machine, the inability to simply be present without evaluating, which Gurdjieff considered a form of spiritual unconsciousness." },
  { id: 540, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 90, track2Day: 40, category: "Panel Wisdom", question: "An advanced One on a panel says: 'I used to think growth meant having better standards. Now I know it means needing standards less.' This reflects:", options: [{ letter: "A", text: "Moral relativism" }, { letter: "B", text: "The shift from ego-driven perfectionism to being-centered acceptance, the core of One transformation" }, { letter: "C", text: "Giving up on improvement" }, { letter: "D", text: "Depression and burnout" }], answer: "B", explanation: "This statement captures the essence of One liberation: the shift from defining themselves by their standards to resting in a deeper okayness that doesn't require constant improvement. Standards may remain, but they no longer define identity or worth." },
  { id: 541, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 91, track2Day: 41, category: "Ichazo Fixations", question: "In Ichazo's 'Enneagon of Anti-Self Actions,' Type 1's anti-self action is 'Over-Perfectionism.' How is this distinguished from ordinary perfectionism?", options: [{ letter: "A", text: "It is more intense" }, { letter: "B", text: "It is turned against the self, the One punishes themselves for being imperfect, creating an inner war that prevents self-acceptance" }, { letter: "C", text: "It applies only to work" }, { letter: "D", text: "There is no distinction" }], answer: "B", explanation: "Anti-self over-perfectionism means the One's standards become weapons against their own being. Every imperfection is experienced as evidence of fundamental unworthiness, creating a cycle of self-punishment that is the antithesis of self-love." },
  { id: 542, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 92, track2Day: 42, category: "Object Relations Deep", question: "From a Hornevian perspective, why is the Type 1 placed in the 'Compliant' group despite sometimes appearing aggressive?", options: [{ letter: "A", text: "It's a classification error" }, { letter: "B", text: "They comply with their internalized moral authority (superego), moving toward people through duty even when their anger suggests otherwise" }, { letter: "C", text: "They are only compliant at work" }, { letter: "D", text: "The aggressive appearance means they're mistyped" }], answer: "B", explanation: "The 'Compliant' classification refers to what the ego complies with. Ones comply with their internalized ideal, they serve, correct, and improve out of duty. Their occasional aggression is still in service of the superego's demands, not a rebellion against it." },
  { id: 543, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 93, track2Day: 43, category: "Counter-Instinctual Combos", question: "How does the sp/so One stack differ from the so/sx One stack in terms of expression?", options: [{ letter: "A", text: "sp/so focuses on personal and community standards quietly; so/sx preaches reform with passionate zeal to social groups" }, { letter: "B", text: "They are the same" }, { letter: "C", text: "sp/so is more emotional; so/sx is more reserved" }, { letter: "D", text: "Neither is a valid stack for Ones" }], answer: "A", explanation: "The sp/so One channels perfectionism first into personal order then community contribution, the quiet pillar of society. The so/sx One leads with social reform energy amplified by sexual intensity, the passionate crusader or moral prophet." },
  { id: 544, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 94, track2Day: 44, category: "Differential Diagnosis", question: "In clinical contexts, Type 1's inner critic can mimic which psychological condition?", options: [{ letter: "A", text: "Bipolar disorder" }, { letter: "B", text: "Obsessive-Compulsive Personality Disorder (OCPD)" }, { letter: "C", text: "Schizophrenia" }, { letter: "D", text: "ADHD" }], answer: "B", explanation: "OCPD shares many surface features with Type 1: preoccupation with orderliness, perfectionism, and control. The distinction is that Type 1 is a motivational pattern (driven by anger/standards) while OCPD is a clinical diagnosis. Many Ones don't meet OCPD criteria." },
  { id: 545, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 95, track2Day: 45, category: "Integration/Disintegration Chains", question: "At Riso-Hudson Level 1 (healthiest), the Type 1 becomes:", options: [{ letter: "A", text: "A perfect rule-follower" }, { letter: "B", text: "A wise, accepting, principled person who embodies discernment without judgment, the 'Wise Realist'" }, { letter: "C", text: "A charismatic leader" }, { letter: "D", text: "An emotionally expressive artist" }], answer: "B", explanation: "At Level 1, the One transcends the inner critic entirely. They retain discernment (the ability to see what could be better) but without compulsive judgment. They accept reality's imperfection with serenity while still working wisely for improvement." },
  { id: 546, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 96, track2Day: 46, category: "Historical Enneagram", question: "Helen Palmer's 'Narrative Tradition' approach to studying Ones involves:", options: [{ letter: "A", text: "Standardized personality testing" }, { letter: "B", text: "Listening to panels of self-identified Ones share their lived experience, revealing patterns from the inside out" }, { letter: "C", text: "Brain imaging studies" }, { letter: "D", text: "Comparing Ones to other types through questionnaires" }], answer: "B", explanation: "Palmer's narrative approach lets Ones speak for themselves in panels, revealing the inner critic's voice, the suppressed anger, and the yearning for serenity in ways that theory alone cannot capture. This first-person data enriches clinical understanding." },
  { id: 547, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 97, track2Day: 47, category: "Panel Wisdom", question: "An advanced practitioner on a panel says: 'The inner critic pretends to be your ally. It says it's keeping you safe. The real work is thanking it and setting it down.' This represents:", options: [{ letter: "A", text: "Cognitive behavioral therapy" }, { letter: "B", text: "The mature One's relationship with their superego, acknowledging its protective function while no longer obeying it" }, { letter: "C", text: "Spiritual bypassing" }, { letter: "D", text: "Denial of the inner critic" }], answer: "B", explanation: "This represents advanced One integration: neither fighting the inner critic nor obeying it, but relating to it with compassion. The critic originally formed to keep the child safe; growth means honoring that while outgrowing its authority." },
  { id: 548, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 98, track2Day: 48, category: "Naranjo's Character Types", question: "Naranjo connected Type 1's character structure to which psychoanalytic concept?", options: [{ letter: "A", text: "Freud's id" }, { letter: "B", text: "The 'anal-retentive' character structure, emphasis on control, order, and retention" }, { letter: "C", text: "Jung's anima" }, { letter: "D", text: "Adler's inferiority complex" }], answer: "B", explanation: "Naranjo explicitly linked the One to the Freudian 'anal character': orderliness, parsimony, and obstinacy born from the developmental stage of learning control. This connection grounds the Enneagram in established psychodynamic theory." },
  { id: 549, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 99, track2Day: 49, category: "Object Relations Deep", question: "In Sandra Maitri's work connecting Enneagram to Essential Aspects, what quality does the One lose contact with?", options: [{ letter: "A", text: "Essential Strength" }, { letter: "B", text: "The quality of 'Brilliancy', the effortless perfection of Being that requires no improvement" }, { letter: "C", text: "Essential Value" }, { letter: "D", text: "The quality of Peace" }], answer: "B", explanation: "Maitri identifies 'Brilliancy' as the essential quality Ones have lost. Brilliancy is the direct experience of reality as already perfect, luminous, whole, and complete without any need for correction. Its loss creates the compensating drive to fix everything." },
  { id: 550, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 100, track2Day: 50, category: "Integration/Disintegration Chains", question: "What is the ultimate sign that a Type 1 has achieved deep integration?", options: [{ letter: "A", text: "They have eliminated all their flaws" }, { letter: "B", text: "They can hold both their desire for goodness and their human imperfection simultaneously, with genuine self-compassion" }, { letter: "C", text: "They no longer care about right and wrong" }, { letter: "D", text: "They become permissive and easygoing about everything" }], answer: "B", explanation: "The integrated One doesn't abandon their values, they hold them lightly. They can say 'I am imperfect AND I am good enough' without contradiction. This paradox, held with genuine compassion, is the One's liberation from the inner critic's tyranny." },
];
